const payload = items[0].json.body;
if (!payload || !payload.githubToken || !payload.githubRepo) {
  return [{ json: { success: false, error: 'Missing githubToken or githubRepo parameters.' } }];
}

const { file, content, commitMessage, branch, githubRepo, githubToken, vercelDeployHook } = payload;
const repoBranch = branch || 'main';

try {
  // 1. Fetch file content metadata to retrieve the current SHA (needed for updates)
  const getRes = await fetch(`https://api.github.com/repos/${githubRepo}/contents/${file}?ref=${repoBranch}`, {
    headers: {
      'Authorization': `token ${githubToken}`,
      'User-Agent': 'autoheal-n8n-bridge',
      'Accept': 'application/vnd.github.v3+json'
    }
  });

  let currentSha = null;
  if (getRes.status === 200) {
    const fileData = await getRes.json();
    currentSha = fileData.sha;
  }

  // 2. Push the commit to GitHub with base64 encoded content
  const base64Content = Buffer.from(content).toString('base64');
  const putRes = await fetch(`https://api.github.com/repos/${githubRepo}/contents/${file}`, {
    method: 'PUT',
    headers: {
      'Authorization': `token ${githubToken}`,
      'Content-Type': 'application/json',
      'User-Agent': 'autoheal-n8n-bridge',
      'Accept': 'application/vnd.github.v3+json'
    },
    body: JSON.stringify({
      message: commitMessage || '🤖 AutoHeal: dynamic code patch evolution',
      content: base64Content,
      sha: currentSha || undefined,
      branch: repoBranch
    })
  });

  const putData = await putRes.json();

  if (putRes.status !== 200 && putRes.status !== 201) {
    return [{ json: { success: false, status: putRes.status, details: putData } }];
  }

  // 3. Trigger Vercel Deploy Hook if provided
  let deployTriggered = false;
  if (vercelDeployHook) {
    try {
      await fetch(vercelDeployHook, { method: 'POST' });
      deployTriggered = true;
    } catch (e) {}
  }

  return [{
    json: {
      success: true,
      commitSha: putData.content?.sha || putData.commit?.sha,
      commitUrl: putData.commit?.html_url,
      deployTriggered
    }
  }];
} catch (err) {
  return [{ json: { success: false, error: err.message } }];
}
